#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;
    sort(nums.begin(), nums.end());
    vector<vector<int>> res;
    function<void(int, int, vector<int>)> dfs = 
        [&] (int target, int index, vector<int> path) {
            if (target < 0) return;
            if (target == 0) {
                res.push_back(path);
                return;
            }
            for (int i = index; i < nums.size(); i++) {
                if (i > index && nums[i] == nums[i-1]) continue;
                path.push_back(nums[i]);
                dfs(target-nums[i], i+1, path);
                path.pop_back();
            }
        };
    dfs(target, 0, {});
    cout << res.size() << endl;
    for (auto x : res) {
        for (auto y : x) cout << y << ' ';
        cout << endl;
    }
    return 0;
}
